import { useEffect, useState } from "react";
import api from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function Home() {
  const [vehicles, setVehicles] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    api.get("/vehicles").then(res => setVehicles(res.data));
  }, []);

  const handleBook = vehicleId => {
    navigate("/login", { state: { vehicleId } });
  };

  return (
    <div style={{ maxWidth: "800px", margin: "20px auto" }}>
      <h1>Available Vehicles</h1>
      {vehicles.map(v => (
        <div key={v._id} style={{ border: "1px solid #ccc", padding: "10px", marginBottom: "10px" }}>
          <p><b>Model:</b> {v.model}</p>
          <p><b>Price:</b> {v.price}</p>
          <button onClick={() => handleBook(v._id)}>Book Appointment</button>
        </div>
      ))}
    </div>
  );
}
